import React from 'react'
import TreeNode from './TreeNode'
function Tree({ treeData }) {
    console.log('treeData', treeData)

    return (
        <ul>
            {
                treeData.map(({ name, id, type, children, isExpanded }) => {
                    return (
                        <TreeNode id={id} name={name} type={type} children={children} isExpanded={isExpanded} />
                    )
                })
            }
        </ul>)

}

export default Tree
